import { useState } from 'react'
import { Button } from '@/components/ui/button'
import { Input } from '@/components/ui/input'
import { Label } from '@/components/ui/label'
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card'
import { FileText, Download, Plus, Trash2 } from 'lucide-react'

const TEMPLATE_NOTA_B64 = ""
const TEMPLATE_EXPTE_B64 = ""

// ─── CONVERSIONES ─────────────────────────────────────────────────────────────
const DIAS: Record<number,string> = {1:'primero',2:'dos',3:'tres',4:'cuatro',5:'cinco',6:'seis',7:'siete',8:'ocho',9:'nueve',10:'diez',11:'once',12:'doce',13:'trece',14:'catorce',15:'quince',16:'dieciséis',17:'diecisiete',18:'dieciocho',19:'diecinueve',20:'veinte',21:'veintiuno',22:'veintidós',23:'veintitrés',24:'veinticuatro',25:'veinticinco',26:'veintiséis',27:'veintisiete',28:'veintiocho',29:'veintinueve',30:'treinta',31:'treinta y uno'}
const MESES_MAP: Record<number,string> = {1:'enero',2:'febrero',3:'marzo',4:'abril',5:'mayo',6:'junio',7:'julio',8:'agosto',9:'septiembre',10:'octubre',11:'noviembre',12:'diciembre'}
const NUMS = ['','uno','dos','tres','cuatro','cinco','seis','siete','ocho','nueve','diez','once','doce','trece','catorce','quince','dieciséis','diecisiete','dieciocho','diecinueve','veinte','veintiuno','veintidós','veintitrés','veinticuatro','veinticinco','veintiséis','veintisiete','veintiocho','veintinueve']
const DECENAS = ['','','veinte','treinta','cuarenta','cincuenta','sesenta','setenta','ochenta','noventa']
const CENTENAS = ['','ciento','doscientos','trescientos','cuatrocientos','quinientos','seiscientos','setecientos','ochocientos','novecientos']

function numLetras(n: number): string {
  if (n===0) return 'cero'
  if (n<30) return NUMS[n]
  if (n<100) { const [d,u]=[Math.floor(n/10),n%10]; return u===0?DECENAS[d]:DECENAS[d]+' y '+NUMS[u] }
  if (n<1000) { const [c,r]=[Math.floor(n/100),n%100]; const base=c===1?'cien':CENTENAS[c]; return r===0?base:base+' '+numLetras(r) }
  if (n<1000000) { const [m,r]=[Math.floor(n/1000),n%1000]; const base=m===1?'mil':numLetras(m)+' mil'; return r===0?base:base+' '+numLetras(r) }
  return String(n)
}

function fechaALetras(s: string): string {
  if (!s) return ''
  const [d,m,a] = s.split('/').map(Number)
  if (!d||!m||!a) return s
  return `${DIAS[d]||numLetras(d)} de ${MESES_MAP[m]} de ${numLetras(a)}`
}

function horaALetras(s: string): string {
  if (!s) return ''
  const [h,m] = s.split(':').map(Number)
  return `${numLetras(h)} horas con ${numLetras(m||0)} minutos`
}

// ─── DOCX ─────────────────────────────────────────────────────────────────────
function base64ToUint8Array(b64: string): Uint8Array {
  const bin = atob(b64)
  const arr = new Uint8Array(bin.length)
  for (let i=0;i<bin.length;i++) arr[i]=bin.charCodeAt(i)
  return arr
}

async function generarDocx(templateB64: string, campos: Record<string,string>): Promise<Uint8Array> {
  const PizZip = (await import('pizzip')).default
  const Docxtemplater = (await import('docxtemplater')).default
  const data = base64ToUint8Array(templateB64)
  const zip = new PizZip(data)
  const doc = new Docxtemplater(zip, { paragraphLoop: true, linebreaks: true, delimiters: { start: '{{', end: '}}' } })
  doc.render(campos)
  return doc.getZip().generate({ type: 'uint8array' })
}

function descargar(bytes: Uint8Array, nombre: string): Promise<void> {
  return new Promise((resolve) => {
    const blob = new Blob([bytes], { type: 'application/vnd.openxmlformats-officedocument.wordprocessingml.document' })
    const url = URL.createObjectURL(blob)
    const a = document.createElement('a')
    a.href = url
    a.download = nombre
    a.style.display = 'none'
    document.body.appendChild(a)
    a.click()
    // Delay revocation so browser has time to start the download
    setTimeout(() => {
      URL.revokeObjectURL(url)
      document.body.removeChild(a)
      resolve()
    }, 1000)
  })
}

// ─── TIPOS ────────────────────────────────────────────────────────────────────
type Comitente = {
  nombre: string
  dni: string
  telefono: string
  domicilio: string
}

type Form = {
  mes: string; año: string; objeto: string
  ubicacion: string; departamento: string
  fecha: string; hora: string
  fecha2: string; hora2: string
}

const FORM_INICIAL: Form = {
  mes:'', año:'', objeto:'Mensura Particular',
  ubicacion:'', departamento:'Capital',
  fecha:'', hora:'', fecha2:'', hora2:'',
}

const COMITENTE_VACIO: Comitente = { nombre:'', dni:'', telefono:'', domicilio:'' }

const MESES_LISTA = ['enero','febrero','marzo','abril','mayo','junio','julio','agosto','septiembre','octubre','noviembre','diciembre']

const S = {
  errorBox: { background:'#FEE2E2', border:'0.5px solid #FCA5A5', borderRadius:'8px', padding:'10px 14px', fontSize:'13px', color:'#991B1B', marginBottom:'12px' } as React.CSSProperties,
  section: { fontSize:'11px', fontWeight:'600', color:'var(--color-text-secondary)', textTransform:'uppercase' as const, letterSpacing:'0.8px', marginTop:'20px', marginBottom:'10px' },
  grid2: { display:'grid', gridTemplateColumns:'1fr 1fr', gap:'12px' } as React.CSSProperties,
  comiteCard: { border:'0.5px solid var(--color-border-tertiary)', borderRadius:'10px', padding:'14px', marginBottom:'10px', background:'var(--color-background-secondary)' } as React.CSSProperties,
  comiteHeader: { display:'flex', justifyContent:'space-between', alignItems:'center', marginBottom:'12px' } as React.CSSProperties,
}

// ─── COMPONENTE ───────────────────────────────────────────────────────────────
export function ExpedienteTab() {
  const [form, setForm] = useState<Form>(FORM_INICIAL)
  const [comitentes, setComitentes] = useState<Comitente[]>([{ ...COMITENTE_VACIO }])
  const [generating, setGenerating] = useState(false)
  const [error, setError] = useState('')

  function setF(k: keyof Form, v: string) { setForm(p => ({ ...p, [k]: v })) }

  function setComitente(i: number, k: keyof Comitente, v: string) {
    setComitentes(prev => prev.map((c, idx) => idx === i ? { ...c, [k]: v } : c))
  }

  function agregarComitente() {
    setComitentes(prev => [...prev, { ...COMITENTE_VACIO }])
  }

  function eliminarComitente(i: number) {
    if (comitentes.length === 1) return
    setComitentes(prev => prev.filter((_, idx) => idx !== i))
  }

  // Formatear múltiples comitentes para el documento
  function formatearComitentes(): { comitente: string; dni: string; telefono: string; domicilio: string } {
    if (comitentes.length === 1) {
      const c = comitentes[0]
      return { comitente: c.nombre, dni: c.dni, telefono: c.telefono, domicilio: c.domicilio }
    }
    // Múltiples: unir nombres con "y", DNIs y demás con " / "
    return {
      comitente: comitentes.map(c => c.nombre).filter(Boolean).join(' y '),
      dni: comitentes.map(c => c.dni).filter(Boolean).join(' / '),
      telefono: comitentes.map(c => c.telefono).filter(Boolean).join(' / '),
      domicilio: comitentes.map(c => c.domicilio).filter(Boolean).join(' / '),
    }
  }

  async function handleGenerar() {
    if (!comitentes[0].nombre.trim()) { setError('El nombre del primer comitente es obligatorio.'); return }
    if (!form.ubicacion.trim()) { setError('El campo Ubicación es obligatorio.'); return }
    setError('')
    setGenerating(true)
    try {
      const { comitente, dni, telefono, domicilio } = formatearComitentes()
      const campos = {
        ...form,
        comitente, dni, telefono, domicilio,
        fecha_texto: fechaALetras(form.fecha),
        hora_texto: horaALetras(form.hora),
        fecha2_texto: fechaALetras(form.fecha2),
        hora2_texto: horaALetras(form.hora2),
      }
      const [notaBytes, expteBytes] = await Promise.all([
        generarDocx(TEMPLATE_NOTA_B64, campos),
        generarDocx(TEMPLATE_EXPTE_B64, campos),
      ])
      const nombreBase = comitente.replace(/\s+/g, '_').substring(0, 40)
      await descargar(notaBytes, `${nombreBase}_Nota_de_Encabezamiento.docx`)
      await descargar(expteBytes, `${nombreBase}_Expediente_de_Mensura.docx`)
    } catch(e: any) {
      setError('Error al generar: ' + (e.message ?? String(e)))
    } finally {
      setGenerating(false)
    }
  }

  function handleLimpiar() {
    setForm(FORM_INICIAL)
    setComitentes([{ ...COMITENTE_VACIO }])
    setError('')
  }

  return (
    <div style={{ maxWidth: '1200px', width: '100%', margin: '0 auto' }} className="grid grid-cols-1 lg:grid-cols-12 gap-6">
      <div className="lg:col-span-8 flex flex-col gap-6">
        <Card>
          <CardHeader>
            <CardTitle style={{ display: 'flex', alignItems: 'center', gap: '8px' }}>
              <FileText style={{ width: '18px', height: '18px', color: '#0F6E56' }} />
              Generar Expediente
            </CardTitle>
            <p style={{ fontSize: '13px', color: 'var(--color-text-secondary)', marginTop: '4px' }}>
              Completá los datos y descargá los dos documentos Word listos para presentar.
            </p>
          </CardHeader>
          <CardContent style={{ display: 'flex', flexDirection: 'column', gap: '20px' }}>
            {error && <div style={S.errorBox}>{error}</div>}

            {/* DATOS GENERALES */}
            <div>
              <div style={S.section}>Datos generales</div>
              <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
                <F label="Mes">
                  <select value={form.mes} onChange={e => setF('mes', e.target.value)}
                    style={{ width: '100%', padding: '8px 10px', borderRadius: '8px', border: '1px solid var(--color-border-tertiary)', fontSize: '13px', background: 'var(--color-background-primary)', color: 'var(--color-text-primary)' }}>
                    <option value="">Seleccioná…</option>
                    {MESES_LISTA.map(m => <option key={m} value={m}>{m}</option>)}
                  </select>
                </F>
                <F label="Año">
                  <Input value={form.año} onChange={e => setF('año', e.target.value)} placeholder="2026" />
                </F>
                <F label="Objeto de mensura">
                  <Input value={form.objeto} onChange={e => setF('objeto', e.target.value)} placeholder="Mensura Particular" />
                </F>
              </div>
            </div>

            {/* INMUEBLE */}
            <div>
              <div style={S.section}>Inmueble</div>
              <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                <F label="Ubicación *">
                  <Input value={form.ubicacion} onChange={e => setF('ubicacion', e.target.value)} placeholder="calle Las Heras 450" />
                </F>
                <F label="Departamento">
                  <Input value={form.departamento} onChange={e => setF('departamento', e.target.value)} placeholder="Capital" />
                </F>
              </div>
            </div>

            {/* COMITENTES */}
            <div>
              <div style={{ ...S.section, display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginTop: '0px' }}>
                <span>Comitentes</span>
                <button
                  onClick={agregarComitente}
                  style={{ background: '#0F6E56', color: 'white', border: 'none', borderRadius: '6px', padding: '4px 10px', fontSize: '11px', cursor: 'pointer', display: 'flex', alignItems: 'center', gap: '4px' }}
                >
                  <Plus style={{ width: '11px', height: '11px' }} />
                  Agregar comitente
                </button>
              </div>

              <div style={{ display: 'flex', flexDirection: 'column', gap: '12px' }}>
                {comitentes.map((c, i) => (
                  <div key={i} style={{ ...S.comiteCard, marginBottom: '0px' }}>
                    <div style={S.comiteHeader}>
                      <span style={{ fontSize: '13px', fontWeight: '500', color: 'var(--color-text-primary)' }}>
                        Comitente {comitentes.length > 1 ? i + 1 : ''}
                      </span>
                      {comitentes.length > 1 && (
                        <button
                          onClick={() => eliminarComitente(i)}
                          style={{ background: 'none', border: 'none', cursor: 'pointer', color: '#D85A30', display: 'flex', alignItems: 'center', gap: '4px', fontSize: '12px' }}
                        >
                          <Trash2 style={{ width: '13px', height: '13px' }} />
                          Eliminar
                        </button>
                      )}
                    </div>
                    <div style={{ display: 'flex', flexDirection: 'column', gap: '10px' }}>
                      <F label={i === 0 ? 'Nombre y apellido *' : 'Nombre y apellido'}>
                        <Input value={c.nombre} onChange={e => setComitente(i, 'nombre', e.target.value)} placeholder="García Juan Carlos" />
                      </F>
                      <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                        <F label="DNI">
                          <Input value={c.dni} onChange={e => setComitente(i, 'dni', e.target.value)} placeholder="32456789" />
                        </F>
                        <F label="Teléfono">
                          <Input value={c.telefono} onChange={e => setComitente(i, 'telefono', e.target.value)} placeholder="3794112233" />
                        </F>
                      </div>
                      <F label="Domicilio">
                        <Input value={c.domicilio} onChange={e => setComitente(i, 'domicilio', e.target.value)} placeholder="San Martín 120" />
                      </F>
                    </div>
                  </div>
                ))}
              </div>
            </div>

            {/* ACTAS */}
            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
              <div>
                <div style={S.section}>Acta de Mensura</div>
                <div className="grid grid-cols-2 gap-3">
                  <F label="Fecha (dd/mm/aaaa)">
                    <Input value={form.fecha} onChange={e => setF('fecha', e.target.value)} placeholder="01/12/2026" />
                  </F>
                  <F label="Hora (hh:mm)">
                    <Input value={form.hora} onChange={e => setF('hora', e.target.value)} placeholder="16:00" />
                  </F>
                </div>
              </div>

              <div>
                <div style={S.section}>Acta de Ausencia de Linderos</div>
                <div className="grid grid-cols-2 gap-3">
                  <F label="Fecha (dd/mm/aaaa)">
                    <Input value={form.fecha2} onChange={e => setF('fecha2', e.target.value)} placeholder="05/12/2026" />
                  </F>
                  <F label="Hora (hh:mm)">
                    <Input value={form.hora2} onChange={e => setF('hora2', e.target.value)} placeholder="09:30" />
                  </F>
                </div>
              </div>
            </div>
          </CardContent>
        </Card>
      </div>

      <div className="lg:col-span-4 flex flex-col gap-6">
        {/* PANEL DE GENERACION */}
        <Card>
          <CardHeader style={{ padding: '16px' }}>
            <CardTitle style={{ fontSize: '15px' }}>Documentos a Generar</CardTitle>
            <p style={{ fontSize: '11px', color: 'var(--color-text-secondary)', marginTop: '2px' }}>
              Los datos se compilarán en las plantillas listas para presentar.
            </p>
          </CardHeader>
          <CardContent style={{ padding: '16px', display: 'flex', flexDirection: 'column', gap: '16px' }}>
            <div style={{ display: 'flex', flexDirection: 'column', gap: '10px' }}>
              <div style={{ display: 'flex', alignItems: 'center', gap: '10px', padding: '10px', borderRadius: '8px', border: '0.5px solid var(--color-border-tertiary)', background: 'var(--color-background-secondary)' }}>
                <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'center', background: '#0F6E5615', color: '#0F6E56', width: '32px', height: '32px', borderRadius: '6px' }}>
                  <FileText style={{ width: '16px', height: '16px' }} />
                </div>
                <div style={{ display: 'flex', flexDirection: 'column' }}>
                  <span style={{ fontSize: '12px', fontWeight: '600' }}>Nota de Encabezamiento</span>
                  <span style={{ fontSize: '10px', color: 'var(--color-text-secondary)' }}>Formalidad de presentación</span>
                </div>
              </div>

              <div style={{ display: 'flex', alignItems: 'center', gap: '10px', padding: '10px', borderRadius: '8px', border: '0.5px solid var(--color-border-tertiary)', background: 'var(--color-background-secondary)' }}>
                <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'center', background: '#0F6E5615', color: '#0F6E56', width: '32px', height: '32px', borderRadius: '6px' }}>
                  <FileText style={{ width: '16px', height: '16px' }} />
                </div>
                <div style={{ display: 'flex', flexDirection: 'column' }}>
                  <span style={{ fontSize: '12px', fontWeight: '600' }}>Expediente de Mensura</span>
                  <span style={{ fontSize: '10px', color: 'var(--color-text-secondary)' }}>Ficha de datos y acta técnica</span>
                </div>
              </div>
            </div>

            {/* Preview conversiones */}
            {(form.fecha || form.hora || form.fecha2 || form.hora2) && (
              <div style={{ background: 'var(--color-background-secondary)', border: '0.5px solid var(--color-border-tertiary)', borderRadius: '8px', padding: '10px 12px', fontSize: '11px', color: 'var(--color-text-secondary)', display: 'flex', flexDirection: 'column', gap: '6px' }}>
                <div style={{ fontSize: '10px', fontWeight: '600', textTransform: 'uppercase', letterSpacing: '0.5px', color: '#0F6E56', marginBottom: '2px' }}>Traducción a Letras</div>
                {form.fecha && <span>📅 Acta Mensura: <strong>{fechaALetras(form.fecha)}</strong></span>}
                {form.hora && <span>🕐 Hora Mensura: <strong>{horaALetras(form.hora)}</strong></span>}
                {form.fecha2 && <span>📅 Acta Ausencia: <strong>{fechaALetras(form.fecha2)}</strong></span>}
                {form.hora2 && <span>🕐 Hora Ausencia: <strong>{horaALetras(form.hora2)}</strong></span>}
              </div>
            )}

            <div style={{ display: 'flex', flexDirection: 'column', gap: '10px', marginTop: '4px' }}>
              <Button onClick={handleGenerar} disabled={generating} style={{ background: '#0F6E56', color: 'white', width: '100%' }}>
                <Download style={{ width: '14px', height: '14px', marginRight: '6px' }} />
                {generating ? 'Generando…' : 'Descargar ambos archivos'}
              </Button>
              <Button variant="outline" onClick={handleLimpiar} style={{ width: '100%' }}>Limpiar formulario</Button>
            </div>

            <p style={{ fontSize: '11px', color: 'var(--color-text-secondary)', textAlign: 'center', lineHeight: '1.4' }}>
              Los archivos se descargarán directamente en formato Word (.docx).
              {comitentes.length > 1 && ` Los ${comitentes.length} comitentes se incluirán de forma conjunta.`}
            </p>
          </CardContent>
        </Card>
      </div>
    </div>
  )
}

function F({ label, children }: { label: string; children: React.ReactNode }) {
  return (
    <div style={{ display:'flex', flexDirection:'column', gap:'6px' }}>
      <Label style={{ fontSize:'13px' }}>{label}</Label>
      {children}
    </div>
  )
}